import React, { createContext, useState, useEffect, useContext } from 'react';
import axios from 'axios';

const AuthContext = createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [currentUser, setCurrentUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Sprawdz token w localStorage
    const storedToken = localStorage.getItem('token');
    const storedUser = localStorage.getItem('user');
    
    if (storedToken && storedUser) {
      setToken(storedToken);
      try {
        setCurrentUser(JSON.parse(storedUser));
      } catch (e) {
        console.error('Błąd parsowania danych użytkownika:', e);
        localStorage.removeItem('user');
        localStorage.removeItem('token');
      }
      
      // Konfiguruj axios z tokenem
      axios.defaults.headers.common['Authorization'] = `Bearer ${storedToken}`;
    }
    
    setLoading(false);
  }, []);

  const login = async (username, password) => {
    try {
      console.log('Wysyłanie zapytania do API:', { username });
      const response = await axios.post('http://localhost:5000/api/login', {
        username,
        password
      });
      
      console.log('Odpowiedź z serwera:', response.data);
      
      // Sprawdzamy strukturę odpowiedzi
      if (!response.data.token || !response.data.user) {
        console.error('Nieprawidłowa struktura odpowiedzi:', response.data);
        return { 
          success: false, 
          error: 'Nieprawidłowa odpowiedź z serwera'
        };
      }
      
      const { token, user } = response.data;
      
      // Zapisz do localStorage
      localStorage.setItem('token', token);
      localStorage.setItem('user', JSON.stringify(user));
      
      // Ustaw w state
      setToken(token);
      setCurrentUser(user);
      
      // Konfiguruj axios z tokenem
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
      
      return { success: true };
    } catch (error) {
      console.error('Błąd podczas logowania:', error);
      return { 
        success: false, 
        error: error.response?.data?.error || 'Wystąpił błąd podczas logowania' 
      };
    }
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setToken(null);
    setCurrentUser(null);
    delete axios.defaults.headers.common['Authorization'];
  };

  const isAuthenticated = () => {
    return !!token;
  };

  const value = {
    currentUser,
    login,
    logout,
    isAuthenticated,
    loading
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
}
